// Both ensures `forall |ki:KeyIterator<K>|` quantifiers share the trigger
// `KeyIterator::between(lo, ki, hi)`, but run-1 binds them against
// `post1_self_@[*ki.get()]` and run-2 against `post2_self_@[*ki.get()]`, so
// z3 never instantiates the two runs at one common `ki`. Pull each run's
// forall into the proof context (re-asserting forces the trigger to fire),
// then drive a pointwise equality over `k: K` using `KeyIterator::new_spec(k)`
// as the *same* witness iterator for both runs.

assert(forall |ki: KeyIterator<K>| #[trigger] KeyIterator::between(lo, ki, hi)
    ==> post1_self_@[*ki.get()] == dst@);
assert(forall |ki: KeyIterator<K>| #[trigger] KeyIterator::between(lo, ki, hi)
    ==> post2_self_@[*ki.get()] == dst@);
assert(forall |ki: KeyIterator<K>| !ki.is_end_spec()
    && !(#[trigger] KeyIterator::between(lo, ki, hi))
    ==> post1_self_@[*ki.get()] == pre_self_@[*ki.get()]);
assert(forall |ki: KeyIterator<K>| !ki.is_end_spec()
    && !(#[trigger] KeyIterator::between(lo, ki, hi))
    ==> post2_self_@[*ki.get()] == pre_self_@[*ki.get()]);

// Pointwise at every `k: K`: lift `k` to a non-end iterator and case-split
// on `KeyIterator::between(lo, ki, hi)`. Either branch pins both views to
// the same value (`dst@` or `pre_self_@[k]`), so the two views agree at `k`.
assert forall |k: K| post1_self_@[k] == post2_self_@[k] by {
    let ki: KeyIterator<K> = KeyIterator::<K>::new_spec(k);
    assert(ki.k === Some(k));
    assert(!ki.is_end_spec());
    assert(*ki.get() == k);
    if KeyIterator::between(lo, ki, hi) {
        assert(post1_self_@[*ki.get()] == dst@);
        assert(post2_self_@[*ki.get()] == dst@);
    } else {
        assert(post1_self_@[*ki.get()] == pre_self_@[*ki.get()]);
        assert(post2_self_@[*ki.get()] == pre_self_@[*ki.get()]);
    }
}

// `valid()` forces a full domain on each view; combined with pointwise
// equality, map extensionality (`=~=`) lifts to whole-view equality.
post1_self_.valid_implies_complete();
post2_self_.valid_implies_complete();
assert(post1_self_@.dom() =~= post2_self_@.dom());
assert(post1_self_@ =~= post2_self_@);
assert(post1_self_@ == post2_self_@);
